// CSD_RATIONALE_BEGIN
// This strategy uses an unconstrained step for the plain text prefix,
// followed by a constrained step to generate exactly one Prover9 formula
// enclosed in << >> delimiters. It handles the grammar strictly within the
// delimited segment.
// CSD_RATIONALE_END

generated := [];

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  if parser.IsCompletePrefix(generated)
  {
    // Generate plain text until we reach the left delimiter
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }
  else
  {
    // Generate a Prover9 formula within the constrained segment
    CSDHelpers.RollbackPreservesTokenInvariant(lm, parser, generated);
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }
}
